'use client';

import { useEffect, useState } from 'react';
import Link from 'next/link';
import {
  getMeetings, createMeeting, getProjects,
  type Meeting, type Project,
} from '@/lib/store';

export default function MeetingsPage() {
  const [meetings, setMeetings] = useState<Meeting[]>([]);
  const [projects, setProjects] = useState<Project[]>([]);
  const [showModal, setShowModal] = useState(false);
  const [form, setForm] = useState({ title: '', projectId: '', scheduledAt: '', participants: '' });
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMeetings(getMeetings());
    setProjects(getProjects());
    setMounted(true);
  }, []);

  const handleCreate = () => {
    if (!form.title.trim()) return;
    createMeeting({
      title: form.title,
      projectId: form.projectId,
      scheduledAt: form.scheduledAt || new Date().toISOString(),
      status: 'scheduled',
      participants: form.participants.split(',').map(p => p.trim()).filter(Boolean),
    });
    setMeetings(getMeetings());
    setShowModal(false);
    setForm({ title: '', projectId: '', scheduledAt: '', participants: '' });
  };

  if (!mounted) return null;

  const scheduled = meetings.filter(m => m.status === 'scheduled');
  const completed = meetings.filter(m => m.status === 'completed');
  const inProgress = meetings.filter(m => m.status === 'in_progress');

  const formatDateTime = (d: string) => {
    if (!d) return '';
    return new Date(d).toLocaleDateString('sv-SE', { weekday: 'short', day: 'numeric', month: 'short', hour: '2-digit', minute: '2-digit' });
  };

  return (
    <>
      <header className="page-header">
        <div>
          <h2>Möten</h2>
          <p className="page-header-subtitle">Planera, transkribera och följ upp möten</p>
        </div>
        <div style={{ display: 'flex', gap: 'var(--space-sm)' }}>
          <Link href="/transcribe" className="btn btn-secondary">🎙️ Starta Live-transkribering</Link>
          <button className="btn btn-primary" onClick={() => setShowModal(true)}>+ Nytt Möte</button>
        </div>
      </header>

      <div className="page-body">
        {/* In Progress */}
        {inProgress.length > 0 && (
          <div style={{ marginBottom: 'var(--space-2xl)' }}>
            <h3 style={{ fontSize: '1rem', fontWeight: 600, marginBottom: 'var(--space-md)', display: 'flex', alignItems: 'center', gap: 'var(--space-sm)' }}>
              <span className="rec-indicator" /> Pågående Möten
            </h3>
            {inProgress.map(m => (
              <Link href={`/transcribe?meetingId=${m.id}`} key={m.id} className="card" style={{ display: 'flex', alignItems: 'center', gap: 'var(--space-md)', textDecoration: 'none', color: 'inherit', marginBottom: 'var(--space-md)', borderColor: 'var(--color-danger)', background: 'rgba(239,68,68,0.05)' }}>
                <span style={{ fontSize: '1.5rem' }}>🎙️</span>
                <div style={{ flex: 1 }}>
                  <div style={{ fontWeight: 600 }}>{m.title}</div>
                  <div style={{ fontSize: '0.8rem', color: 'var(--text-tertiary)' }}>Startad {formatDateTime(m.startedAt || '')}</div>
                </div>
                <span className="badge badge-danger">● Live</span>
              </Link>
            ))}
          </div>
        )}

        {/* Scheduled */}
        <div style={{ marginBottom: 'var(--space-2xl)' }}>
          <h3 style={{ fontSize: '1rem', fontWeight: 600, marginBottom: 'var(--space-md)', color: 'var(--text-secondary)' }}>
            📅 Kommande ({scheduled.length})
          </h3>
          <div className="card">
            {scheduled.length === 0 ? (
              <div className="empty-state">
                <span className="empty-state-icon">📅</span>
                <h3>Inga kommande möten</h3>
                <p>Skapa ett nytt möte eller starta en transkribering direkt.</p>
              </div>
            ) : scheduled.map(meeting => {
              const project = projects.find(p => p.id === meeting.projectId);
              return (
                <div key={meeting.id} className="list-item">
                  <span style={{ fontSize: '1.3rem' }}>📅</span>
                  <div className="list-item-content">
                    <div className="list-item-title">{meeting.title}</div>
                    <div className="list-item-subtitle">
                      {formatDateTime(meeting.scheduledAt)}
                      {project && ` · ${project.name}`}
                      {meeting.participants.length > 0 && ` · ${meeting.participants.join(', ')}`}
                    </div>
                  </div>
                  <div style={{ display: 'flex', gap: 'var(--space-sm)' }}>
                    <Link href={`/transcribe?meetingId=${meeting.id}`} className="btn btn-primary btn-sm">
                      🎙️ Transkribera
                    </Link>
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        {/* Completed */}
        {completed.length > 0 && (
          <div>
            <h3 style={{ fontSize: '1rem', fontWeight: 600, marginBottom: 'var(--space-md)', color: 'var(--text-secondary)' }}>
              ✅ Avslutade ({completed.length})
            </h3>
            <div className="card">
              {completed.map(meeting => {
                const project = projects.find(p => p.id === meeting.projectId);
                return (
                  <div key={meeting.id} className="list-item">
                    <span style={{ fontSize: '1.3rem' }}>📋</span>
                    <div className="list-item-content">
                      <div className="list-item-title">{meeting.title}</div>
                      <div className="list-item-subtitle">
                        {formatDateTime(meeting.endedAt || meeting.scheduledAt)}
                        {project && ` · ${project.name}`}
                        {meeting.transcript.length > 0 && ` · ${meeting.transcript.length} segment`}
                      </div>
                    </div>
                    {meeting.summary && <span className="badge badge-success">Sammanfattat</span>}
                  </div>
                );
              })}
            </div>
          </div>
        )}
      </div>

      {/* Modal */}
      {showModal && (
        <div className="modal-overlay" onClick={() => setShowModal(false)}>
          <div className="modal" onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <h3>Nytt Möte</h3>
              <button className="btn btn-ghost btn-icon" onClick={() => setShowModal(false)}>✕</button>
            </div>
            <div className="modal-body">
              <div className="form-group">
                <label className="form-label">Mötestitel</label>
                <input className="input" placeholder="T.ex. Sprint Planning Vecka 17" value={form.title} onChange={e => setForm({ ...form, title: e.target.value })} autoFocus />
              </div>
              <div className="form-group">
                <label className="form-label">Projekt (valfritt)</label>
                <select className="input" value={form.projectId} onChange={e => setForm({ ...form, projectId: e.target.value })}>
                  <option value="">Inget projekt</option>
                  {projects.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
                </select>
              </div>
              <div className="form-group">
                <label className="form-label">Tid</label>
                <input className="input" type="datetime-local" value={form.scheduledAt} onChange={e => setForm({ ...form, scheduledAt: e.target.value })} />
              </div>
              <div className="form-group">
                <label className="form-label">Deltagare (kommaseparerade)</label>
                <input className="input" placeholder="Anna, Erik, Maria" value={form.participants} onChange={e => setForm({ ...form, participants: e.target.value })} />
              </div>
            </div>
            <div className="modal-footer">
              <button className="btn btn-secondary" onClick={() => setShowModal(false)}>Avbryt</button>
              <button className="btn btn-primary" onClick={handleCreate}>Skapa Möte</button>
            </div>
          </div>
        </div>
      )}
    </>
  );
}
